 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import HyperConvergedModel from '@kubevirt-ui/kubevirt-api/console/models/HyperConvergedModel';
 5	import useHyperConvergeConfiguration from '@kubevirt-utils/hooks/useHyperConvergeConfiguration';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getResourceUrl } from '@kubevirt-utils/resources/shared';
 8	import { isEmpty } from '@kubevirt-utils/utils/utils';
 9	import { PrometheusEndpoint, usePrometheusPoll } from '@openshift-console/dynamic-plugin-sdk';
10	import { Skeleton, StackItem } from '@patternfly/react-core';
11	
12	import ConditionIcon from './ConditionIcon';
13	import { HCO_HEALTH_METRIC, VALUE_TO_LABLE } from './constants';
14	
15	const Conditions: FC = () => {
16	  const { t } = useKubevirtTranslation();
17	  const [hyperConverge, hyperLoaded] = useHyperConvergeConfiguration();
18	
19	  const [queryData, loaded] = usePrometheusPoll({
20	    endpoint: PrometheusEndpoint.QUERY,
21	    query: HCO_HEALTH_METRIC,
22	  });
23	
24	  const condition = queryData?.data?.result?.[0]?.value?.[1];
25	
26	  const label = VALUE_TO_LABLE[condition];
27	
28	  if (!loaded || !hyperLoaded)
29	    return (
30	      <StackItem>
31	        <Skeleton screenreaderText="Loading contents" />
32	      </StackItem>
33	    );
34	
35	  if (isEmpty(condition)) return null;
36	
37	  return (
38	    <>
39	      <StackItem>
40	        <div className="kv-health-popup__title">{t('Conditions')}</div>
41	      </StackItem>
42	      <StackItem className="kv-health-popup__alerts-count">
43	        <ConditionIcon conditionValue={condition} />
44	        <Link to={getResourceUrl({ model: HyperConvergedModel, resource: hyperConverge })}>
45	          {label}
46	        </Link>
47	      </StackItem>
48	    </>
49	  );
50	};
51	
52	export default Conditions;

